import React, { useState, useEffect } from 'react';
import axios from 'axios';

const Shop = () => {
  const [products, setProducts] = useState([]);
  const [loading, setLoading] = useState(true);
  const [category, setCategory] = useState('');

  useEffect(() => {
    fetchProducts();
  }, []);

  const fetchProducts = async () => {
    try {
      const response = await axios.get('http://localhost:5000/api/products');
      setProducts(response.data);
      setLoading(false);
    } catch (error) {
      console.error('Erreur:', error);
      setLoading(false);
    }
  };

  const filteredProducts = category 
    ? products.filter(p => p.category === category)
    : products;

  if (loading) return <h1>Chargement...</h1>;

  return (
    <div style={{ padding: '30px' }}>
      <h1>🛍️ Boutique</h1>

      <div style={{ marginBottom: '20px' }}>
        <button onClick={() => setCategory('')} style={{ marginRight: '10px' }}>Tous</button>
        <button onClick={() => setCategory('homme')} style={{ marginRight: '10px' }}>👨 Hommes</button>
        <button onClick={() => setCategory('femme')} style={{ marginRight: '10px' }}>👩 Femmes</button>
        <button onClick={() => setCategory('unisexe')}>✨ Unisexe</button>
      </div>

      <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fill, minmax(250px, 1fr))', gap: '20px' }}>
        {filteredProducts.map(product => (
          <div key={product._id} style={{ border: '1px solid #ddd', padding: '15px', borderRadius: '8px' }}>
            {product.image && <img src={product.image} alt={product.name} style={{ width: '100%', height: '200px', objectFit: 'cover', borderRadius: '6px' }} />}
            <h3>{product.name}</h3>
            <p>{product.description}</p>
            <p><strong>Prix:</strong> {product.price}€</p>
            <p><strong>Stock:</strong> {product.stock}</p>
            <p><strong>Note:</strong> ⭐ {product.rating}</p>
            <button style={{ width: '100%', padding: '10px', background: '#667eea', color: 'white', border: 'none', borderRadius: '6px', cursor: 'pointer' }}>
              Ajouter au panier
            </button>
          </div>
        ))}
      </div>

      {filteredProducts.length === 0 && <p>Aucun produit trouvé</p>}
    </div>
  );
};

export default Shop;
